#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 1e5+5 , M = 10;
LL n,m,s[N][M],lst[M],Ans=-1;
pLL a[N],tmp[M];unordered_map<ULL,LL> mp;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(pLL p1,pLL p2){return p1>p2;}
ULL Hash(int st,int id){
    ULL res=0;int bg=0;
    for(;bg<8;bg++)if(st&(1<<bg))break;
    for(int i=bg+1;i<8;i++)
        if(st&(1<<i))res=res*1000+s[id][i]-s[id][bg];
    return res;
}
int main(){
    n=read(),m=read()-1;
    for(int i=1;i<=n;i++)a[i]={read(),read()-1};
    sort(a+1,a+n+1);
    for(int i=1;i<=n;i++){
        mp[0]=a[i].fr;
        for(int j=0;j<8;j++)s[i][j]=s[i-1][j];
        s[i][a[i].se]++;
        for(int j=lst[a[i].se]+1;j<=i;j++){
            int st=0;
            for(int k=0;k<8;k++)
                if(s[i-1][k]-s[j-1][k])st|=(1<<k);
            mp.erase(Hash(st,j-1));
            st|=(1<<a[i].se);
            ULL Hsh=Hash(st,j-1);
            if(!mp.count(Hsh))mp[Hsh]=a[j].fr;
        }lst[a[i].se]=i;
        for(int j=0;j<8;j++)tmp[j]={lst[j],j};
        sort(tmp,tmp+8,cmp);int st=0;
        for(int j=0;j<m;j++)st|=(1<<tmp[j].se);
        for(int j=m;j<8&&tmp[j].fr;j++){
            st|=(1<<tmp[j].se);ULL Hsh=Hash(st,i);
            if(mp.count(Hsh))Ans=max(Ans,a[i].fr-mp[Hsh]);
        }
    }cout<<Ans<<"\n";
    return 0;
}
